import Button from "@/components/Button/Button";
import SelectField from "@/components/Form/SelectField";
import { useUserStore } from "@/stores/userStore";
import Link from "next/link";
import { useEffect } from "react";
import Cookies from "js-cookie";
import { formatToRupiah } from "@/utils/formatter/formatToRupiah";
import Spinner from "@/components/Loading/Spinner";

export default function Home() {
  const userId = Cookies.get("userId");
  const { user, getUser, isLoading, error } = useUserStore();

  useEffect(() => {
    if (userId != undefined) {
      const getData = async (userId: string) => {
        await getUser(userId!);
      };
      getData(userId!);
    }
  }, [getUser, userId]);

  return (
    <div className="min-h-screen">
      <div className=" flex flex-col pt-36 items-center justify-center gap-20 px-[20%] z-20">
        <h1 className="text-[40px] text-center">
          Send package anywhere in Indonesia
        </h1>
        <form className="flex flex-col gap-4 w-full">
          <div>
            <p className="text-xl font-semibold">Origin</p>
            <div className="flex gap-4">
              <SelectField
                id="provinceOrigin"
                name="provinceOrigin"
                placeholder="Choose origin province"
                options={[]}
                value=""
                onChange={() => {}}
              />

              <SelectField
                id="origin"
                name="origin"
                placeholder="Choose origin city"
                options={[]}
                value=""
                onChange={() => {}}
              />
            </div>
          </div>
          <div>
            <p className="text-xl font-semibold">Destination</p>
            <div className="flex gap-4">
              <SelectField
                id="provinceDes"
                name="provinceDes"
                options={[]}
                value=""
                placeholder="Choose destination province"
                onChange={() => {}}
              />
              <SelectField
                id="destination"
                name="destination"
                options={[]}
                value=""
                placeholder="Choose destination city"
                onChange={() => {}}
              />
            </div>
          </div>
          <p className="text-primary text-center">
            Estimated Cost: Rp 20.000,00
          </p>
          <div className="mt-10 w-full">
            <Button variants="primary">Proceed to Complete Shipment</Button>
          </div>
        </form>
      </div>
      {userId != undefined && error != "" ? (
        <div className="text-center">
          There is something wrong when fetching the data, please refresh the
          page
        </div>
      ) : (
        <div className="w-full flex flex-col items-center mt-">
          <div className="bg-white border-4 border-solid border-primary rounded-3xl flex flex-col items-center w-[400px] px-8 py-6 mt-14 gap-4">
            <div className="flex flex-col items-center">
              <p className="text-[28px]">Your Balance</p>
              {isLoading ? (
                <Spinner />
              ) : userId === undefined ? (
                <p className="text-[28px] font-bold">
                  <Link href={"/auth/login"} className="text-primary underline">
                    Login
                  </Link>{" "}
                  to see your balance.
                </p>
              ) : (
                <p className="text-[28px] font-bold">
                  {user && formatToRupiah(user.balance)}
                </p>
              )}
            </div>
            <Link href={"/"} className="text-primary underline">
              Top up Balance
            </Link>
          </div>
        </div>
      )}

      {/* <div className="absolute bg-primary w-full h-[150px] bottom-0 z-0"></div> */}
    </div>
  );
}
